class MainOrchestrator:
    def __init__(self):
        self.running = False
        self.loop_interval = 1

    def start(self):
        self.running = True
        print('Orquestrador iniciado')
        self.run_loop()

    def stop(self):
        self.running = False
        print('Orquestrador parado')

    def run_loop(self):
        while self.running:
            try:
                response = response_detector.detect()
                if response:
                    command = command_parser.parse(response)
                    if command:
                        result = self.execute_command(command)
                        feedback_sender.send_success('Comando executado: ' + str(command))
                time.sleep(self.loop_interval)
            except Exception as e:
                feedback_sender.send_error('Erro no orquestrador: ' + str(e))
                time.sleep(self.loop_interval)

    def execute_command(self, command):
        cmd_name = command.get('command')
        args = command.get('args')
        if cmd_name == 'digitar-texto':
            pyautogui.typewrite(args)
        return True

if __name__ == '__main__':
    orchestrator = MainOrchestrator()
    print('Iniciando Main Orchestrator...')
    try:
        orchestrator.start()
    except KeyboardInterrupt:
        orchestrator.stop()
        print('Orquestrador finalizado')

