import re

class CommandParser:
    def __init__(self):
        self.command_prefix = '@#$-'
        self.commands = {}

    def parse(self, text):
        if text.startswith(self.command_prefix):
            command = text[len(self.command_prefix):]
            return self.extract_command_and_args(command)
        return None

    def extract_command_and_args(self, command_text):
        parts = command_text.split(' ', 1)
        cmd = parts[0]
        args = parts[1] if len(parts) > 1 else ''
        return {'command': cmd, 'args': args}

    def register_command(self, name, handler):
        self.commands[name] = handler

    def execute(self, text):
        parsed = self.parse(text)
        if parsed and parsed['command'] in self.commands:
            return self.commands[parsed['command']](parsed['args'])
        return None

command_parser = CommandParser()

