import threading
import time
from screen_reader import screen_reader

class ScreenMonitor:
    def __init__(self, interval=2):
        self.running = False
        self.interval = interval
        self.thread = None
        self.last_content = None

    def start(self):
        self.running = True
        self.thread = threading.Thread(target=self._monitor)
        self.thread.daemon = True
        self.thread.start()
        print('Screen monitor iniciado')

    def stop(self):
        self.running = False
        if self.thread:
            self.thread.join()
        print('Screen monitor parado')

    def _monitor(self):
        while self.running:
            try:
                content = screen_reader.get_screen_content()
                self.last_content = content
                time.sleep(self.interval)
            except Exception as e:
                print('Erro no monitor: ' + str(e))
                time.sleep(self.interval)

    def get_last_content(self):
        return self.last_content

screen_monitor = ScreenMonitor()
